fn solve(sx: i64, sy: i64, tx: i64, ty: i64) -> i64 {
    if sx == tx && sy == ty {
        return 0;
    }

    let mut x = sx;
    let mut y = sy;
    let mut steps = 0;

    while x < tx || y < ty {
        let m = std::cmp::max(x, y);
        if x < tx && y < ty {
            // If both coordinates are less than target, we can increase either
            // but we need to choose the one that gets us closer to the target
            if tx - x > ty - y {
                x += m;
            } else {
                y += m;
            }
        } else if x < tx {
            x += m;
        } else {
            y += m;
        }
        steps += 1;
    }

    if x == tx && y == ty {
        steps
    } else {
        -1
    }
}
